INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('murder_scene', 'Mordplatsen', 'Sveavägen 44, hörnet av Tunnelgatan. Utanför Dekorima konstbutik. En man ligger på den snöiga trottoaren i en pöl av blod. En kvinna knäböjer bredvid honom. Människor samlas.', 59.340722, 18.059444, 'primary', 1);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('tunnelgatan_stairs', 'Trappan på Tunnelgatan', '89 branta, snöiga trappsteg upp genom Brunkebergsåsen. Gärningsmannens flyktväg österut.', 59.34078, 18.0612, 'escape_route', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('david_bagares_gata', 'David Bagares gata', 'Toppen av trappan vid Malmskillnadsgatan. Gärningsmannen halkade i snön här.', 59.34048, 18.0632, 'escape_route', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('grand_cinema', 'Biografen Grand', 'Sveavägen nära Tegnérgatan. Palme och hans fru såg \'Bröderna Mozart\' här. Publiken har precis släppts ut.', 59.3433, 18.0587, 'origin', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('skandia_entrance', 'Skandias entré', 'Huvudentrén till Skandia-huset, ca 60 meter norr om mordplatsen. En man i 50-årsåldern står här och verkar ivrig att prata.', 59.3413, 18.0595, 'suspect_link', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('dekorima_doorway', 'Dekorimas dörröppning', 'Dörröppningen till konstbutiken Dekorima på hörnet. Skydd för vittnen efter skotten.', 59.34075, 18.05955, 'scene_detail', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('sabbatsberg_hospital', 'Sabbatsbergs sjukhus', 'Cirka 1 km bort. Ambulansen anlände 23:31. Palme förklarades död kl 00:06.', 59.3437, 18.0484, 'aftermath', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('adolf_fredriks_church', 'Adolf Fredriks kyrka', 'Kyrkan mitt på Sveavägen. Paret Palme korsade gatan här — från västra till östra sidan.', 59.3418, 18.0578, 'route', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('taxi_position', 'Taxins position', 'Anders Delsborns Järfälla-taxi. Härifrån gick det första fungerande larmet till polisen.', 59.34085, 18.0592, 'scene_detail', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('polishuset_kungsholmen', 'Polishuset på Kungsholmen', 'Stockholmspolisens högkvarter. Härifrån leddes utredningen. Hans Holmér höll dagliga presskonferenser. 700 000 sidor dokument, 10 000+ förhörda, 738 testade vapen.', 59.3326, 18.039, 'investigation', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('petterssons_bostad', 'Christer Petterssons bostad', 'I förorten Rotebro/Sollentuna, norr om Stockholm. Här bodde den man som dömdes — och frikändes — för mordet på Palme. Lars Jeppsson, vittnet som jagade gärningsmannen, bodde nästan grannar med Pettersson.', 59.485, 17.938, 'suspect_link', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('cedergrens_lagenhet', 'Sigge Cedergrens lägenhet', 'Härifrån hävdade narkotikalangaren Sigge Cedergren att han lånat ett vapen till Christer Pettersson. Men telefonavlyssningen visar att han var hemma och pratade i telefon vid mordtillfället. Hans berättelse ändrades 43 gånger.', 59.342, 18.068, 'suspect_link', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('rosenbad', 'Rosenbad — Regeringskansliet', 'Palmes arbetsplats. Här skickade han hem livvakterna vid lunch. Här hade han möten med Iraks ambassador och Norges ambassador under sin sista dag. Här tog han beslutet att gå hem till fots — utan skydd.', 59.3289, 18.0644, 'origin', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('gamla_stan_palmes_bostad', 'Palmes bostad, Västerlånggatan 31', 'Paret Palmes lägenhet i Gamla Stan. Härifrån gick de till tunnelbanan, tog tuben till Rådmansgatan och promenerade till Grand. Walkie-talkie-vittnen rapporterade övervakare redan från Gamla Stan.', 59.3247, 18.0689, 'route', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('sydafrikanska_sparet', 'Sydafrikanska spåret', 'Ett utredningsrum för att utforska Sydafrika-kopplingen. SADF:s dokument, Operation Long Reach, Craig Williamson, Eugene de Kock. En vecka före mordet höll Palme huvudtalet mot apartheid.', 59.336, 18.055, 'investigation', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('adolf_fredriks_kyrkogard', 'Adolf Fredriks kyrkogård — Palmes grav', 'Olof Palme är begravd här. 125 länder skickade delegationer till begravningen i Blå Hallen den 15 mars 1986. Halva Tunnelgatan döptes om till Olof Palmes gata.', 59.342, 18.0567, 'aftermath', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('stay_behind_thulehuset', 'Stay Behind-högkvarteret (Thulehuset)', 'Sveriges hemliga Stay Behind-nätverk leddes av Alvar Lindencrona med kontor i Thulehuset på Sveavägen — samma byggnad som mordplatsen och Skandia-huset. Bekräftat av general Bengt Gustafsson 1990.', 59.3409, 18.0595, 'conspiracy', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('rotebro_narkotikamiljon', 'Rotebro — Narkotikamiljön', 'Christer Petterssons hemvist i Sollentuna. Här cirkulerade vapen, amfetamin och rykten i Stockholms undre värld. Stulna revolvrar bytte händer som betalning för skulder.', 59.4847, 17.9342, 'secondary', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('pkk_lokalen', 'PKK-lokalen — Holmérs spår', 'Hans Holmér lade enorma resurser på det kurdiska spåret. PKK-aktivister i Stockholm övervakades, förhördes och infiltrerades — men spåret ledde ingenstans.', 59.3325, 18.025, 'secondary', 0);
INSERT INTO locations (id, name, description, lat, lng, type, unlocked_by_default) VALUES ('telefonkiosken', 'Telefonkiosken vid Tunnelgatan', 'En gul Televerket-kiosk nära mordplatsen. Vittnen rapporterade att en man ringde härifrån strax efter skotten. 1986 var detta det enda sättet att kommunicera i realtid utan walkie-talkie.', 59.3378, 18.0594, 'secondary', 0);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_escape_tunnelgatan', 'Flyktväg: Tunnelgatan', 'Gärningsmannen joggar österut längs Tunnelgatan mot trappan efter skotten.', 'escape_route', 'tunnelgatan_stairs');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_top_of_stairs', 'Toppen av trappan', 'Gärningsmannen sprang uppför alla 89 trappsteg och försvann på David Bagares gata.', 'escape_route', 'david_bagares_gata');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_cinema_origin', 'Bion: Grand', 'Paret Palme kom från biografen Grand. De lämnade ca 23:10.', 'origin', 'grand_cinema');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_blue_jacket_man', 'Mannen i blå dunjacka', 'Lisbeth Palme beskrev gärningsmannen i blå dunjacka — men det stämmer troligen med vittnet Björkman.', 'contradiction', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_dark_coat_hat', 'Mörk rock och stickad mössa', 'Flera vittnen beskriver mörk fladdrande rock till knäna och mössa uppvikt i kanten.', 'suspect_description', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_no_hat_conflict', 'Ingen mössa?', 'Minst tre vittnen säger bestämt att gärningsmannen INTE bar mössa.', 'contradiction', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_hand_on_shoulder', 'Handen på axeln', 'Gärningsmannen la sin hand på Palmes axel innan han sköt.', 'method', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_killer_waited', 'Gärningsmannen väntade', 'Morelius såg gärningsmannen stå och vänta på hörnet i flera minuter innan skotten.', 'method', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_professional_killer', 'Professionell utförare?', 'Morelius: \'Lugnt och professionellt. Nästan en elitsoldat.\'', 'theory', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_two_men', 'Två män på platsen', 'Lisbeth sa till polisen att hon sett två män — gärningsmannen och en som stirrade.', 'suspect_description', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_second_person_south', 'Någon sprang söderut', 'Ljungqvist kan ha sett en person springa söderut — motsatt riktning. En medbrottsling?', 'escape_route', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_taxi_alert', 'Taxilarmet', 'Delsborns larm via Järfälla Taxi nådde polisen kl 23:23:40 — det första fungerande larmet.', 'aftermath', 'taxi_position');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_failed_alarm', 'Det felkopplade nödsamtalet', 'Första nödsamtalet kopplades fel. Prioritetsmekanismen var avstängd. Polislarm gick ut 02:05.', 'investigation_failure', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_long_barrel', 'Lång pipa', 'Delsborn: revolvern hade en ovanligt lång pipa. Stämmer med Smith & Wesson .357 Magnum.', 'weapon', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_clutch_bag', 'Liten väska', 'Nieminen: gärningsmannen höll en liten väska (10x15 cm) han verkade öppna/stänga. Gömde vapnet?', 'suspect_description', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_disappeared_east', 'Försvann österut', 'Gärningsmannen försvann österut på David Bagares gata. Ingen polisavspärrning.', 'escape_route', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_not_pettersson', 'Inte Christer Pettersson', 'Jeppsson, som kände Pettersson, svär på att gärningsmannen inte var han.', 'suspect_exclusion', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_hospital_transport', 'Transport till Sabbatsberg', 'Ambulans stoppades av en förbipasserande. Avgick 23:28, ankom 23:31. Palme dog 00:06.', 'aftermath', 'sabbatsberg_hospital');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_skandia_worker', 'Skandia-huset', 'Mordplatsen ligger utanför Skandia-huset. En anställd stämplade ut 23:19, två minuter före skotten.', 'suspect_link', 'skandia_entrance');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_bjorkman_doorway', 'Dekorimas dörröppning', 'Björkman sökte skydd i Dekorimas dörr. Lisbeth stirrade på honom och förväxlade honom troligen med mördaren.', 'scene_detail', 'dekorima_doorway');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_bofors_connection', 'Bofors-kopplingen', 'Björkman jobbar på Bofors-företag. Bofors sålde vapen till Indien — affär värd 1,4 miljarder dollar.', 'theory', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_walkie_talkies', 'Walkie-talkies', 'Ca 30 vittnen rapporterade män med walkie-talkies längs parets rutt. Minst en talade tyska/afrikaans.', 'conspiracy', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_military_surveillance', 'Militär övervakning', 'Anna Hage kontaktades av en man i militäruniform: \'Vi måste hålla landet lugnt.\'', 'conspiracy', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_engstrom_inconsistencies', 'Engströms motstridiga berättelser', 'Hans berättelse ändrades mellan förhör. Inget vittne bekräftar hans version.', 'suspect_link', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_engstrom_weapon_knowledge', 'Engströms vapenkunskap', '\'Jag skulle ha valt en mindre kaliber... om jag hade varit mördaren.\' Skyttemedlem. Illustrerade militärmanualer.', 'suspect_link', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_engstrom_impossible_knowledge', 'Engström vet för mycket', 'Kan beskriva saker bara gärningsmannen kunde sett — men inte saker som hände efteråt.', 'suspect_link', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_crossing_street', 'De korsade gatan', 'Paret korsade Sveavägen vid Adolf Fredriks kyrka — från västra till östra sidan.', 'route', 'adolf_fredriks_church');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_investigation_failures', 'Utredningens misslyckanden', 'Inga vägspärrar. Brottsplatsen säkrades inte. Formell undersökning började kl 10:00 nästa morgon — 11 timmar efter mordet. Generellt polislarm gick inte ut förrän 02:05.', 'investigation_failure', 'polishuset_kungsholmen');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_no_crime_scene_seal', 'Brottsplatsen förseglades aldrig', 'Medborgare lade blommor, fotgängare trampade genom området. Polisen missade kulorna. Formell brottsplatsundersökning påbörjades först kl 10:00 den 1 mars.', 'investigation_failure', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_bullet_chain_of_evidence', 'Ifrågasatt beviskedja — kulorna', 'Båda kulorna hittades av CIVILPERSONER, inte polisen. Ovanligt intakta. Inga spår av blod eller vävnad. Winchester-Western .357 Magnum, 158 grain, metallgenomträngande.', 'weapon', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_pettersson_trial', 'Rättegången mot Christer Pettersson', 'Dömd till livstid av tingsrätten 1989 (6 nämndemän mot 2 yrkesdomare). Enhälligt frikänd av Svea hovrätt. Lisbeth Palmes identifiering kallades \'extremt grovt felaktig\'.', 'suspect_link', 'petterssons_bostad');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_lineup_errors', 'Vittneskonfrontationens brister', 'Lisbeth informerades FÖRE konfrontationen att den misstänkte var alkoholist. \'Man kan lätt se vem som är alkoholist.\' Hovrätten kallade detta \'extremt grova fel.\'', 'investigation_failure', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_cedergren_weapon', 'Cedergrens vapen — Sucksdorff-revolvern', 'Sigge Cedergren hävdade på sin dödsbädd att han lånat en revolver till Pettersson. Stulen från filmaren Arne Sucksdorff 1977. Polisen Thure Nässén förhörde Cedergren 43 gånger. Vapnet återfanns aldrig.', 'weapon', 'cedergrens_lagenhet');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_mockfjard_weapon', 'Mockfjärdsvapnet', 'Smith & Wesson Model 28 stulen i Haparanda 1983. Användes vid postrån i Mockfjärd. Blyisotopanalys bekräftade SAMMA sammansättning som mordkulorna. Bärgat 2006 — för rostigt för att avgöra.', 'weapon', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_south_africa_motive', 'Sydafrikas motiv', 'SADF:s dokument 15 okt 1985: Palme \'ska ses som en fiende till staten.\' En vecka före mordet höll Palme talet \'Apartheid kan inte reformeras, det måste avskaffas.\' Tommy Lindström utpekade 2010 Sydafrika som sin främsta misstanke.', 'conspiracy', 'sydafrikanska_sparet');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_operation_long_reach', 'Operation Long Reach', 'Sydafrikas program för mord utanför landets gränser. Lett av Craig Williamson. Eugene de Kock vittnade 1996 att operationen \'spelade en roll\' i Palme-mordet. Anthony White utpekades som skytten.', 'conspiracy', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_no_bodyguards', 'Inga livvakter', 'Palme skickade hem SÄPO-livvakterna vid lunch den 28 februari. Biobeslutet togs senare. Enligt sonen försökte Palme ringa livvakterna innan — fick inget svar.', 'method', 'rosenbad');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_sapo_operation', 'SÄPO:s hemliga operation \'Cosi fan tutte\'', 'SÄPO körde en hemlig operation i Stockholm mordnatten med kodnamnet \'Cosi fan tutte\'. Syftet har aldrig avslöjats. SÄPO:s akt om Palme — öppnad på 1950-talet — \'försvann.\'', 'conspiracy', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_walkie_surveillance_route', 'Övervakningsrutten', 'Ca 30 vittnen rapporterade män med walkie-talkies längs HELA Palmes rutt. SÄPO-rapport 1986: \'Analysen stöder att Palme var under övervakning från bostaden till mordet.\'', 'conspiracy', 'gamla_stan_palmes_bostad');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_stay_behind', 'Stay Behind-nätverket', 'Sveriges hemliga Stay Behind-nätverk (NATO:s Gladio) leddes från Thulehuset på Sveavägen — samma byggnad som mordplatsen. Medlemmar hade högerextrema sympatier och tillgång till vapen.', 'conspiracy', 'stay_behind_thulehuset');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_pkk_trail', 'PKK-spåret — det stora misstaget', 'Hans Holmér fixerade vid PKK. \'Operation Alpha\' 20 jan 1987: 200 poliser grep 22 kurder utan bevis. Alla släpptes. Åratal av resurser slösades.', 'investigation_failure', 'pkk_lokalen');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_ebbe_carlsson_affair', 'Ebbe Carlsson-affären', 'Förläggaren Ebbe Carlsson fortsatte PKK-utredningen privat med stöd från justitieministern. Fick illegal avlyssningsutrustning. Avslöjades 1988. Justitieministern tvingades avgå.', 'investigation_failure', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_bofors_deep', 'Bofors-affären på djupet', 'Kontrakt värt 1,4 miljarder dollar signerat 24 mars 1986. Mutor på 9 miljoner dollar. Carl Algernon, statens vapeninspektör, föll framför tunnelbanevagn i januari 1987 — 30 min efter möte med Nobel Industries-chefen.', 'conspiracy', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_police_trail', 'Polisspåret — Basebolligan', 'Poliser med nazisympatier: Östling (samma ovanliga ammo), Åkerbring (skålade med champagne), Piltz (walkie-talkie), Djurfeldt (stod ovanför Tunnelgatan med revolver). SOU 1999:88: \'Kan inte uteslutas.\'', 'conspiracy', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_phantom_sketch', 'Fantombilden — det falska spåret', 'Släppt 6 mars 1986. Genererade 7 000–8 000 tips — alla falska. Kvinnan tog senare avstånd. Bilden styrde utredningen i månader och anses idag värdelös.', 'investigation_failure', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_engstrom_death', 'Engströms död år 2000', 'Hittades död 26 juni 2000 med tom whiskeyflaska och smärtstillande. Aldrig formellt förhörd som misstänkt — bara som \'vittne.\' Hans död möjliggjorde nedläggningen utan rättegång.', 'suspect_link', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_2020_conclusion', 'Proklamationen 2020 — och återkallelsen 2025', '10 juni 2020: åklagare Petersson pekade ut Engström. 18 dec 2025: överåklagare Gune ändrade beslutet — Engström inte längre misstänkt. Lisbeths identifiering av Pettersson oförenlig med Engström.', 'aftermath', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_134_confessions', '134 falska bekännelser', '134 falska bekännelser. 700 000 sidor dokument. 10 000+ förhör. 22 430 utredningspunkter. Över 600 miljoner kronor. Den största kriminalutredningen i svensk historia.', 'investigation_failure', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_aftermath_funeral', 'En nations förlust av oskuld', 'Första mordet på en svensk nationsledare sedan Gustav III 1792. 125 nationer vid begravningen. Nordic noir-genren (Stieg Larsson, Henning Mankell) spåras direkt till 1986.', 'aftermath', 'adolf_fredriks_kyrkogard');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_palme_hatred', 'Palmehat — fenomenet', 'Sveriges mest polariserande politiker. Marcherade med Nordvietnams ambassador. Jämförde USA:s bombningar med Treblinka. Tidskriften Contra distribuerade darttavlor med Palmes ansikte.', 'theory', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_gh_suspect_weapon', 'Det otestade vapnet', 'Den enda registrerade .357 Magnumen i Stockholmsregionen lämnades aldrig in för testning. Ägaren sköt sig själv när polisen kom 2008. Det enda potentiella mordvapnet som aldrig testades.', 'weapon', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_rosengrens_erbjudande', 'Skjutsen som aldrig erbjöds', 'TCO-ordföranden Björn Rosengren träffade Palme i biografens foajé. Efter filmen övervägde han att erbjuda paret skjuts hem — men hans fru sa att man inte ska störa. Om han hade erbjudit skjutsen hade Palme aldrig gått på Sveavägen.', 'witness', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_8_unidentified_cinema', '8 oidentifierade biobesökare', 'Av 206 besökare på kvällsföreställningen identifierade polisen 198. Åtta förblev anonyma. Vilka var de? Varför kunde de inte spåras? I en utredning med 700 000 sidor är detta ett anmärkningsvärt hål.', 'contradiction', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_grand_man_surveillance', 'Grand-mannens blick', 'Bland de oidentifierade biobesökarna fanns uppgifter om en ensam man som inte verkade intresserad av filmen — utan av publiken, och specifikt av paret Palme. Övervakare inne i biografen?', 'witness', 'telefonkiosken');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_bio_decision_paradox', 'Det oplanerade biobesöket', 'Beslutet att gå på bio fattades bara timmar innan. Lisbeth ringde Mårten kl 17:00, Olof fick veta vid middagen kl 18:30. Ingen livvakt informerades. Ändå rapporterade ~30 vittnen walkie-talkie-män längs hela rutten. Hur visste mördaren?', 'timeline', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_skandia_multiple', 'Flera Skandia-anställda vid platsen', 'Inte bara Engström — flera anställda vid Skandia befann sig i området den kvällen. Skandias kontor låg vid Sveavägen/Kungsgatan, ett naturligt rörelsestråk. Slump — eller organiserad närvaro?', 'witness', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_skandia_wallenberg', 'Skandia → Wallenberg → Bofors', 'Skandias styrelse hade överlappningar med Bofors/Nobel Industries via Wallenberg-sfären. Samma ägargrupp kontrollerade försäkringsbolaget och vapentillverkaren. En röd tråd genom den svenska finanseliten.', 'connection', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_lisbeth_two_men', 'Lisbeth såg två män', 'På Sabbatsbergs sjukhus berättade Lisbeth Palme för kriminalinspektör Åke Rimborn att hon sett TVÅ män vid mordplatsen. Hennes ord: "Känner ni inte igen mig? Jag är Lisbeth Palme, för fan, och där ligger min man Olof!"', 'witness', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_crime_scene_11_hours', '11 timmar utan brottsplatsundersökning', 'Den formella kriminaltekniska undersökningen påbörjades inte förrän kl 10:00 den 1 mars — nästan 11 timmar efter mordet. Mordplatsen kontaminerades av blommor, fotgängare och journalister. Båda kulorna hittades av civila, inte av polis.', 'contradiction', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_163_minutes_alarm', '163 minuter till generallarm', 'Polisen visste senast kl 23:30 att statsministern var offret. Ändå dröjde det till 02:05 — 163 minuter — innan ett generellt polislarm gick ut. Inga vägspärrar upprättades. Mördaren hade hela natten på sig att försvinna.', 'timeline', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_ostling_taxi_south', 'Östlings taxi söderut', 'En taxichaufför uppgav att han plockat upp en passagerare nära mordplatsen 4-5 minuter efter skotten — beskrivningen stämde med Basebolligan-polisen Carl Gustav Östling. Östling hade sjukanmält sig just den 28 februari. Hans alibi kontrollerades aldrig tillfredsställande.', 'witness', 'rotebro_narkotikamiljon');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_ostling_ammo_match', 'Östlings identiska ammunition', 'Carl Gustav Östling — Basebolligan-polis med dokumenterade nazistsympatier — ägde Winchester-Western .357 Magnum metallgenomträngande ammunition. Exakt samma typ som mordammunitionen. SOU 1999:88 konstaterade att hans alibi aldrig kontrollerades.', 'physical', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_djurfeldt_above_escape', 'Djurfeldt ovanför flyktvägen', 'Basebolligan-polisen Claes Djurfeldt befann sig i en piketbuss på Malmskillnadsgatan — direkt ovanför mördarens flyktväg via trapporna. Han hade lämnat bussen ensam och stod utomhus vid tidpunkten för skotten. Hemma hade han samma ammunition som mordvapnet.', 'connection', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_metal_piercing_police', 'Polisammunition', 'Winchester-Western .357 Magnum metal-piercing — extremt ovanlig i civilt bruk. Såldes primärt till polismyndigheter. Krävde speciallicens. Hade inget jaktändamål. Två Basebolligan-poliser (Östling och Djurfeldt) ägde exakt denna typ.', 'physical', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_738_weapons_none', '738 testade vapen — inget matchade', 'Under utredningen testskjöts 738 vapen, varav ~500 var Magnum-revolvrar. Inget matchade mordkulornas räfflingsmönster. Mordvapnet har aldrig hittats. Det enda registrerade .357-vapnet i Stockholm som aldrig testades — ägaren sköt sig själv när polisen kom.', 'physical', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_pg_vinge_dismissal', 'SÄPO-chefen som Palme sparkade', 'P.G. Vinge, SÄPO-chef 1962-1970, avsattes av Palme efter att ha karakteriserat honom som kommunistsympatisör. Vinges avsättning skapade en institutionell spricka — SÄPO uppfattade Palme som en chef som förnedrat deras ledare.', 'connection', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_sapo_file_missing', 'SÄPO:s Palme-akt "kan inte återfinnas"', 'SÄPO öppnade en akt om Palme på 1950-talet. Den innehöll kartläggning av internationella kontakter och bedömningar av "ideologisk pålitlighet". När mordutredarna begärde akten rapporterade SÄPO att den inte kunde återfinnas. Aldrig förklarat.', 'contradiction', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_cosi_fan_tutte_mozart', 'Così fan tutte — Mozart-ringen', 'SÄPO körde en hemlig operation mordnatten med kodnamnet "Così fan tutte" — en Mozart-opera. Filmen Palme såg hette "Bröderna Mozart" och handlade om Don Giovanni — också en Mozart-opera med samma librettist. Kodnamnet och filmvalet bildar en makaber Mozart-ring. Tillfällighet — eller insiderskämt?', 'contradiction', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_gladio_weapons', 'Stay Behind — vapen utanför statlig kontroll', 'NATO:s hemliga Stay Behind-nätverk bekräftades 1990. I Italien kopplades det till terroristdåd, i Belgien till massakrer. Det svenska nätverket hade vapengömslen, radioutrustning och falska ID-handlingar. Rekryteringsprofil: högerkonservativa med anti-Palme-sentiment.', 'connection', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_ib_affair', 'IB-affären — den hemliga byrån', 'IB (Informationsbyrån) var en hemlig militär underrättelseorganisation som registrerade svenska medborgare och delade information med CIA och Mossad. Avslöjades 1973 av Jan Guillou. IB opererade under socialdemokratiska regeringar men tjänade amerikanska intressen.', 'connection', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_svartenbrandt_hints', 'Svartenbrandt vet mer', 'Lars-Inge Svartenbrandt — en av Sveriges mest kända kriminella — förnekade all inblandning i Palme-mordet men antydde att han "visste mer" än han berättade. Han sa vid ett tillfälle att "sanningen aldrig kommer fram." Sigge Cedergren pekade ut honom som inblandad.', 'witness', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_sucksdorff_stolen_weapon', 'Filmaren Sucksdorffs stulna revolver', 'Den Oscar-belönade dokumentärfilmaren Arne Sucksdorff fick en Smith & Wesson .357 Magnum stulen. Tjuven var vän med Sigge Cedergren. Vapnet matchade i typ och kaliber — men hittades aldrig. En möjlig väg: filmare → tjuv → Cedergren → Pettersson → mordplatsen.', 'physical', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_33_aringen_signalement', '33-åringens signalement', 'En man med kodnamnet "33-åringen" pekades ut av flera oberoende vittnen som närvarande vid mordplatsen. Hans signalement matchade delvis gärningsmannen. Han hade vapenkontakter och kopplingar till kretsar där Smith & Wesson-revolvrar cirkulerade. Identiteten förblir hemlig — förundersökningssekretess.', 'witness', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_ted_gardestad_tragedy', 'Ted Gärdestads tragedi', 'Sigge Cedergren pekade även ut sångaren Ted Gärdestad som inblandad — en grundlös anklagelse. Ryktena läckte till pressen och förstörde den psykiskt sköre Gärdestad. Han tog sitt liv 1997. Utredningens destruktiva kraft — inte alla spår leder till sanning, och falska spår har verkliga offer.', 'contradiction', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_pkk_holmer_obsession', 'Holmérs PKK-besatthet', 'Hans Holmér lade enorma resurser på PKK-spåret. Kurdiska aktivister i Stockholm infiltrerades och förhördes. Men spåret kollapsade — det fanns inga bevis för PKK-inblandning. Holmérs fixering vid PKK har tolkats som ett medvetet försök att styra bort utredningen från andra spår.', 'connection', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_phone_booth_after_shots', 'Samtalet från telefonkiosken', 'En man observerades ringa från en telefonkiosk nära mordplatsen strax efter skotten. 1986 krävde realtidskommunikation walkie-talkies eller telefonkiosker. Om samtalet var en signal — "uppdraget utfört" — pekar det mot en organiserad operation.', 'witness', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_barnvagn_witness', 'Kvinnan med barnvagnen', 'En kvinna med barnvagn på Sveavägen kl 23:15 i -6°C. En ovanlig observation — varför var hon ute vid den tiden? I underrättelsesammanhang används barnvagnar som täckmantel. Eller bara en förälder vars barn bara somnade i vagnen.', 'witness', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_akerbring_champagne', 'Champagnetoasten', 'Basebolligan-polisen Stellan Åkerbring skålade med champagne dagen efter mordet för att fira Palmes död. En polis som gråter vid sin statsministers kropp — och en annan som firar med champagne. Hela spännvidden i det svenska polisväsendets relation till Palme.', 'contradiction', NULL);
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_svartenbrandt_connection', 'Svartenbrandts nätverk', 'Sigge Cedergren nämnde inte bara Pettersson — han pekade även ut den beryktade tjuven Lars-Inge Svartenbrandt och sångaren Ted Gärdestad. Svartenbrandt hade vapenkontakter och rörde sig i samma kretsar som Pettersson. Han rymde från fängelset minst 7 gånger.', 'connection', 'rotebro_narkotikamiljon');
INSERT INTO clues (id, title, description, type, unlocks_location_id) VALUES ('clue_palme_last_meetings', 'Palmes sista möten', 'Den 28 februari träffade Palme Iraks ambassadör al-Sahaf (Palme medlade i Iran-Irak-kriget), fondförvaltare (börsskatten hade höjts), och Norges ambassadör. Han ringde finansminister Feldt om sjunkande SIFO-siffror. Sedan skickade han hem livvakterna. Vilka av dessa möten triggade hans död?', 'timeline', NULL);
